// ===================== STORAGE HELPERS =====================
function lzSave(key,val){
  try{localStorage.setItem(key,LZString.compressToUTF16(JSON.stringify(val)));}
  catch(e){console.warn('lzSave failed:',key,e);}
}
function lzLoad(key,fallback){
  try{
    const raw=localStorage.getItem(key);
    if(!raw)return fallback;
    // Try LZ decompress first (new compressed format)
    try{
      const dec=LZString.decompressFromUTF16(raw);
      if(dec){const parsed=JSON.parse(dec);return parsed;}
    }catch(e){}
    // Fall back to plain JSON (old pre-compression format) and auto-migrate
    try{
      const parsed=JSON.parse(raw);
      lzSave(key,parsed);// migrate to compressed format in place
      return parsed;
    }catch(e){}
    return fallback;
  }catch(e){return fallback;}
}

// ===================== STATE =====================
let activeData=null,currentPlant=null,currentTab='heatmap';
let hmMode='range',trendMode='inverter',distMode='capacity';
let tableSortCol='avgPerf',tableSortAsc=false,blacklistTarget=null;
let lastFleetAvg=null;
let activeFilters={roof:new Set(),inv:new Set(),tilt:new Set(),az:new Set(),cap:new Set()};
let notes={},blacklist={},overlay=null;
let trendChart=null,distChart=null;

// ===================== INIT =====================
function init(){
  loadLocalStorage();mergeData();buildPlantSelect();setDefaultDates();
  updateDatasetInfo();renderHistory();
  const plants=Object.keys(activeData.plants).sort();
  if(plants.length){document.getElementById('plant-select').value=plants[0];onPlantChange();}
}
function loadLocalStorage(){
  notes=JSON.parse(localStorage.getItem('cmes_notes')||'{}');
  blacklist=JSON.parse(localStorage.getItem('cmes_blacklist')||'{}');
  try{
    const p=lzLoad('cmes_data_overlay',null);
    if(p){if(p.version===DATA_VERSION)overlay=p.data;else localStorage.removeItem('cmes_data_overlay');}
  }catch(e){overlay=null;}
}
function reparseMeta(m){
  const p=parseLabel(m.label);
  if(!p)return m;
  return{...m,plant:p.plant,roof:p.roof,inverter:p.inverter,module:p.module,string:p.string};
}
function mergeData(){
  const base={dates:[...EMBEDDED.dates],plants:{}};
  for(const[p,pd]of Object.entries(EMBEDDED.plants)){
    base.plants[p]={strings:{}};
    for(const[l,s]of Object.entries(pd.strings))base.plants[p].strings[l]={m:reparseMeta(s.m),d:{...s.d}};
  }
  if(!overlay){activeData=base;return;}
  const merged={dates:[...new Set([...base.dates,...(overlay.dates||[])])].sort(),plants:{...base.plants}};
  if(overlay.plants)for(const[p,pd]of Object.entries(overlay.plants)){
    if(!merged.plants[p])merged.plants[p]={strings:{}};
    for(const[l,s]of Object.entries(pd.strings||{})){
      if(!merged.plants[p].strings[l])merged.plants[p].strings[l]={m:reparseMeta(s.m),d:{}};
      for(const[d,v]of Object.entries(s.d||{}))if(!(d in merged.plants[p].strings[l].d))merged.plants[p].strings[l].d[d]=v;
    }
  }
  activeData=merged;
}
function buildPlantSelect(){
  const sel=document.getElementById('plant-select'),cur=sel.value;
  sel.innerHTML='';
  for(const p of Object.keys(activeData.plants).sort()){const o=document.createElement('option');o.value=o.textContent=p;sel.appendChild(o);}
  if(cur&&activeData.plants[cur])sel.value=cur;
}
function setDefaultDates(){
  const d=activeData.dates,from=d[0],to=d[d.length-1];
  ['date-from','hm-from'].forEach(id=>document.getElementById(id).value=from);
  ['date-to','hm-to','hm-day'].forEach(id=>document.getElementById(id).value=to);
  document.getElementById('last-updated-badge').textContent='Updated: '+to;
}

// ===================== NAV =====================
function switchTab(tab){
  currentTab=tab;document.body.className='tab-'+tab;
  document.querySelectorAll('.nav-item').forEach(el=>el.classList.remove('active'));
  document.querySelectorAll('.tab-panel').forEach(el=>el.classList.remove('active'));
  document.querySelectorAll('.nav-item').forEach(el=>{if((el.getAttribute('onclick')||'').includes("'"+tab+"'"))el.classList.add('active');});
  const panel=document.getElementById('tab-'+tab);if(panel)panel.classList.add('active');
  if(tab==='heatmap')renderHeatmap();
  else if(tab==='analysis')renderAnalysis();
  else if(tab==='report'){initReportTab();setTimeout(()=>renderReportPreview(),100);}
  else if(tab==='ai'){initAITab();}
  else{updateDatasetInfo();renderHistory();}
}

// ===================== DATES =====================
function activeDates(){
  const from=document.getElementById('date-from').value,to=document.getElementById('date-to').value;
  const exclWE=document.getElementById('excl-weekends').checked;
  return activeData.dates.filter(d=>{
    if(d<from||d>to)return false;
    if(exclWE){const day=new Date(d+'T00:00:00').getDay();if(day===0||day===6)return false;}
    return true;
  });
}
function hmDates(){
  const exclWE=document.getElementById('excl-weekends').checked;
  if(hmMode==='day')return[document.getElementById('hm-day').value];
  const from=document.getElementById('hm-from').value,to=document.getElementById('hm-to').value;
  return activeData.dates.filter(d=>{
    if(d<from||d>to)return false;
    if(exclWE){const day=new Date(d+'T00:00:00').getDay();if(day===0||day===6)return false;}
    return true;
  });
}
function onPlantChange(){
  currentPlant=document.getElementById('plant-select').value;
  activeFilters={roof:new Set(),inv:new Set(),tilt:new Set(),az:new Set(),cap:new Set()};
  buildFilters();refreshAllViews();
}
function onDateChange(){refreshAllViews();}
function refreshAllViews(){
  if(currentTab==='heatmap')renderHeatmap();
  else if(currentTab==='analysis')renderAnalysis();
}

// ===================== STRINGS =====================
function plantStrings(){
  if(!currentPlant||!activeData.plants[currentPlant])return[];
  return Object.values(activeData.plants[currentPlant].strings);
}
function filteredStrings(){
  return plantStrings().filter(s=>{
    const m=s.m;
    if(activeFilters.roof.size&&!activeFilters.roof.has(m.roof))return false;
    if(activeFilters.inv.size&&!activeFilters.inv.has(m.inverter))return false;
    if(activeFilters.tilt.size&&!activeFilters.tilt.has(tiltBucket(m.tilt)))return false;
    if(activeFilters.az.size&&!activeFilters.az.has(azBucket(m.azimuth)))return false;
    if(activeFilters.cap.size&&!activeFilters.cap.has(capBucket(m.capacity)))return false;
    return true;
  });
}
function avgPerf(s,dates){
  const vals=dates.map(d=>s.d[d]).filter(v=>v!==undefined&&v!==null);
  return vals.length?vals.reduce((a,b)=>a+b,0)/vals.length:null;
}
function perfColor(v){
  if(v===null||v===undefined)return'#374151';
  if(v<0)return'#7f1d1d';
  if(v<0.5)return'#dc2626';
  if(v<0.7)return lerpColor('#dc2626','#f97316',(v-0.5)/0.2);
  if(v<0.85)return lerpColor('#f97316','#eab308',(v-0.7)/0.15);
  if(v<0.93)return lerpColor('#eab308','#84cc16',(v-0.85)/0.08);
  return lerpColor('#84cc16','#16a34a',Math.min((v-0.93)/0.07,1));
}
function lerpColor(a,b,t){
  const ar=parseInt(a.slice(1,3),16),ag=parseInt(a.slice(3,5),16),ab=parseInt(a.slice(5,7),16);
  const br=parseInt(b.slice(1,3),16),bg=parseInt(b.slice(3,5),16),bb=parseInt(b.slice(5,7),16);
  return'#'+[ar+(br-ar)*t,ag+(bg-ag)*t,ab+(bb-ab)*t].map(v=>Math.round(v).toString(16).padStart(2,'0')).join('');
}
function tiltBucket(v){return(v===null||v===undefined)?'N/A':Math.round(v)+'°';}
function azBucket(v){return(v===null||v===undefined)?'N/A':(Math.round(v/10)*10)+'°';}
function capBucket(v){return(v===null||v===undefined)?'N/A':parseFloat(v.toFixed(2))+' kWp';}

// ===================== FILTERS =====================
// Cascading logic: Plant → Roof → Inverter → (Tilt, Azimuth, Capacity in parallel)
// Each tier shows only values present in strings that pass all upstream filters.
// Selecting a tier prunes invalid selections from all downstream tiers.

function stringsPassingRoof(){
  // Strings that pass the roof filter (used to compute valid inverters)
  return plantStrings().filter(s=>{
    if(activeFilters.roof.size&&!activeFilters.roof.has(s.m.roof))return false;
    return hasData(s);
  });
}
function stringsPassingInverter(){
  // Strings that pass roof + inverter filter (used to compute valid tilt/az/cap)
  return stringsPassingRoof().filter(s=>{
    if(activeFilters.inv.size&&!activeFilters.inv.has(s.m.inverter))return false;
    return true;
  });
}
function hasData(s){
  // Only show strings with at least one performance value
  return Object.keys(s.d).length>0;
}

function buildFilters(){
  const allWithData=plantStrings().filter(hasData);
  const dates=activeDates();

  // ROOF — from all plant strings with data; hide '1 Zone' if real roofs also exist
  const allRoofs=[...new Set(allWithData.map(x=>x.m.roof))].sort();
  const realRoofs=allRoofs.filter(r=>r!=='1 Zone');
  const roofs=realRoofs.length>0?realRoofs:allRoofs;

  // INVERTER — from strings that pass the roof filter
  const afterRoof=stringsPassingRoof();
  const invs=[...new Set(afterRoof.map(x=>x.m.inverter))].sort((a,b)=>(parseInt(a.replace(/\D/g,''))||0)-(parseInt(b.replace(/\D/g,''))||0));

  // TILT / AZ / CAP — from strings that pass roof + inverter
  const afterInv=stringsPassingInverter();
  const tilts=[...new Set(afterInv.map(x=>tiltBucket(x.m.tilt)))].filter(v=>v!=='N/A').sort((a,b)=>parseFloat(a)-parseFloat(b));
  const azs=[...new Set(afterInv.map(x=>azBucket(x.m.azimuth)))].filter(v=>v!=='N/A').sort((a,b)=>parseFloat(a)-parseFloat(b));
  const caps=[...new Set(afterInv.map(x=>capBucket(x.m.capacity)))].filter(v=>v!=='N/A').sort((a,b)=>parseFloat(a)-parseFloat(b));

  // Prune stale active selections (values that no longer exist in the valid set)
  pruneStale('roof', new Set(roofs));
  pruneStale('inv',  new Set(invs));
  pruneStale('tilt', new Set(tilts));
  pruneStale('az',   new Set(azs));
  pruneStale('cap',  new Set(caps));

  buildChipGroup('filter-roof',    'Roof',     roofs, 'roof');
  buildChipGroup('filter-inv',     'Inverter', invs,  'inv');
  buildChipGroup('filter-tilt',    'Tilt',     tilts, 'tilt');
  buildChipGroup('filter-az',      'Azimuth',  azs,   'az');
  buildChipGroup('filter-cap',     'Capacity', caps,  'cap');
}

function pruneStale(key, validSet){
  for(const v of [...activeFilters[key]]){
    if(!validSet.has(v)) activeFilters[key].delete(v);
  }
}

function buildChipGroup(id,label,vals,key){
  const el=document.getElementById(id);
  // Map group id → its preceding separator id
  const sepMap={
    'filter-inv':'fsep-inv','filter-tilt':'fsep-tilt',
    'filter-az':'fsep-az','filter-cap':'fsep-cap'
  };
  if(!vals.length){
    el.innerHTML='';
    if(sepMap[id]) document.getElementById(sepMap[id]).style.display='none';
    return;
  }
  if(sepMap[id]) document.getElementById(sepMap[id]).style.display='';
  el.innerHTML=`<span class="filter-label">${label}</span>`;
  vals.forEach(v=>{
    const c=document.createElement('span');
    c.className='chip'+(activeFilters[key].has(v)?' active':'');
    c.textContent=v;
    c.onclick=()=>toggleFilter(key,v);
    el.appendChild(c);
  });
}

function toggleFilter(key,val){
  if(activeFilters[key].has(val)) activeFilters[key].delete(val);
  else activeFilters[key].add(val);
  // Rebuild downstream filters to reflect new valid values
  buildFilters();
  refreshAllViews();
}

// ===================== DEVIATION =====================
function onThresholdChange(val){
  document.getElementById('threshold-val').textContent=val+'%';
  refreshAllViews();
}
function getThreshold(){return parseInt(document.getElementById('threshold-slider').value)/100;}
// Returns fleet avg (0-1) of all non-blacklisted strings over given dates
function getFleetAvg(strings,dates){
  const active=strings.filter(s=>!blacklist[s.m.label]);
  const perfs=active.map(s=>avgPerf(s,dates)).filter(v=>v!==null);
  return perfs.length?perfs.reduce((a,b)=>a+b,0)/perfs.length:null;
}
// Returns absolute performance cutoff (0-1): strings below this are flagged
function getPerfCutoff(strings,dates){
  const fa=getFleetAvg(strings,dates);
  return fa!==null?fa*(1-getThreshold()):null;
}

// ===================== HEATMAP =====================
function setHmMode(mode){
  hmMode=mode;
  document.getElementById('hm-controls-range').style.display=mode==='range'?'flex':'none';
  document.getElementById('hm-controls-day').style.display=mode==='day'?'flex':'none';
  document.getElementById('hm-mode-range').classList.toggle('active',mode==='range');
  document.getElementById('hm-mode-day').classList.toggle('active',mode==='day');
  renderHeatmap();
}
function updateHmPanelTitle(){
  const plant=currentPlant||'—';
  const dateStr=hmMode==='day'
    ?(document.getElementById('hm-day').value||'—')
    :(document.getElementById('hm-from').value||'—')+' → '+(document.getElementById('hm-to').value||'—');
  const modeLabel=hmMode==='day'?'single day':'date range';
  document.getElementById('hm-panel-title').textContent=
    `String Performance Heatmap — ${plant} · ${dateStr} (${modeLabel})`;
}
function renderHeatmap(){
  if(currentTab!=='heatmap')return;
  updateHmPanelTitle();
  const wrap=document.getElementById('heatmap-wrap');
  if(!currentPlant){wrap.innerHTML='<div style="padding:60px;text-align:center;color:var(--text-dim);font-size:13px">Select a plant to view the heatmap</div>';return;}
  const strings=filteredStrings(),dates=hmDates(),threshold=getThreshold();
  lastFleetAvg=getFleetAvg(strings,dates);
  if(!strings.length){wrap.innerHTML='<div style="padding:60px;text-align:center;color:var(--text-dim)">No strings match current filters</div>';return;}
  if(hmMode==='range')renderHeatmapRange(wrap,strings,dates,threshold);
  else renderHeatmapDay(wrap,strings,dates[0],threshold);
}

// DATE RANGE MODE: Rows = strings (grouped Roof→Inverter), Columns = dates
function renderHeatmapRange(wrap,strings,dates,threshold){
  const _fa=getFleetAvg(strings,dates);
  const cutoff=_fa!==null?_fa*(1-threshold):null;
  const byRoof={};
  for(const s of strings){
    const r=s.m.roof,inv=s.m.inverter;
    if(!byRoof[r])byRoof[r]={};
    if(!byRoof[r][inv])byRoof[r][inv]=[];
    byRoof[r][inv].push(s);
  }
  const ncols=dates.length+2;
  let h='<table class="heatmap"><thead><tr>';
  h+='<th class="th-label">String</th>';
  for(const d of dates){
    const day=new Date(d+'T00:00:00').getDay(),isSun=day===0;
    h+=`<th class="${isSun?'sunday':''}" style="min-width:64px;text-align:center">${d.slice(5)}</th>`;
  }
  h+='<th class="avg-col" style="min-width:60px;text-align:center">Avg</th></tr></thead><tbody>';

  for(const roof of Object.keys(byRoof).sort()){
    h+=`<tr class="hm-group-roof"><td colspan="${ncols}">🏠 ${roof}</td></tr>`;
    const invs=Object.keys(byRoof[roof]).sort((a,b)=>(parseInt(a.replace(/\D/g,''))||0)-(parseInt(b.replace(/\D/g,''))||0));
    for(const inv of invs){
      h+=`<tr class="hm-group-inv"><td colspan="${ncols}" style="padding-left:32px!important">⚡ ${inv}</td></tr>`;
      for(const s of byRoof[roof][inv].sort((a,b)=>{
        const ma=parseInt(a.m.module.replace(/\D/g,''))||0,mb=parseInt(b.m.module.replace(/\D/g,''))||0;
        if(ma!==mb)return ma-mb;
        return(parseInt(a.m.string.replace(/\D/g,''))||0)-(parseInt(b.m.string.replace(/\D/g,''))||0);
      })){
        const ap=avgPerf(s,dates),isBL=!!blacklist[s.m.label],isUnder=cutoff!==null&&ap!==null&&ap<cutoff&&!isBL;
        const apColor=ap!==null?perfColor(ap):'#374151';
        h+=`<tr class="${isBL?'blacklisted':''}${isUnder?' underperform-row':''}">`;
        h+=`<td class="td-label">${isBL?'⊘ ':''}${s.m.module}-${s.m.string}</td>`;
        for(const d of dates){
          const v=s.d[d];const c=v!==undefined&&v!==null?perfColor(v):null;
          const txt=v!==undefined&&v!==null?Math.round(v*100):'—';
          if(c) h+=`<td class="td-cell"><div class="cell-inner cell-solid" style="background:${c}">${txt}</div></td>`;
          else h+=`<td class="td-cell"><div class="cell-inner cell-empty">—</div></td>`;
        }
        const avgTxt=ap!==null?Math.round(ap*100)+'%':'—';
        h+=`<td class="td-cell"><div class="cell-inner" style="color:${apColor};font-weight:700">${avgTxt}</div></td>`;
        h+='</tr>';
      }
    }
  }
  h+='</tbody></table>';wrap.innerHTML=h;
}

// SINGLE DAY MODE: Rows = Module-String pairs (grouped Roof→Module sub-header), Columns = Inverters
function renderHeatmapDay(wrap,strings,date,threshold){
  if(!date){wrap.innerHTML='<div style="padding:60px;text-align:center;color:var(--text-dim)">Select a date</div>';return;}
  if(threshold===undefined)threshold=getThreshold();
  const _dayVals=strings.filter(s=>!blacklist[s.m.label]).map(s=>s.d[date]).filter(v=>v!==null&&v!==undefined);
  const _dayFleetAvg=_dayVals.length?_dayVals.reduce((a,b)=>a+b,0)/_dayVals.length:null;
  const cutoff=_dayFleetAvg!==null?_dayFleetAvg*(1-threshold):null;

  // Separate strings into those with a real inverter vs no inverter (N/A)
  const invStrings=strings.filter(s=>s.m.inverter&&s.m.inverter!=='N/A');
  const noInvStrings=strings.filter(s=>!s.m.inverter||s.m.inverter==='N/A');

  // Columns = unique real inverters, sorted numerically
  const invSet=new Set();
  for(const s of invStrings) invSet.add(s.m.inverter);
  const inverters=[...invSet].sort((a,b)=>{
    const na=parseInt(a.replace(/\D/g,''))||0,nb=parseInt(b.replace(/\D/g,''))||0;
    return na!==nb?na-nb:a.localeCompare(b);
  });

  // Build grid: byRoof[roof][module][pv][inverter] = string obj  (inverter-based strings only)
  const byRoof={};
  for(const s of invStrings){
    const{roof,inverter,module,string:pv}=s.m;
    if(!byRoof[roof])byRoof[roof]={mods:{},plain:[]};
    if(!byRoof[roof].mods[module])byRoof[roof].mods[module]={};
    if(!byRoof[roof].mods[module][pv])byRoof[roof].mods[module][pv]={};
    byRoof[roof].mods[module][pv][inverter]=s;
  }
  // Also collect no-inverter strings per roof
  for(const s of noInvStrings){
    const{roof}=s.m;
    if(!byRoof[roof])byRoof[roof]={mods:{},plain:[]};
    byRoof[roof].plain.push(s);
  }

  const ncols=inverters.length+1;
  let h='<table class="heatmap"><thead><tr>';
  h+='<th class="th-label">Module · String</th>';
  for(const inv of inverters) h+=`<th style="min-width:72px;text-align:center">${inv}</th>`;
  h+='</tr></thead><tbody>';

  for(const roof of Object.keys(byRoof).sort()){
    h+=`<tr class="hm-group-roof"><td colspan="${ncols}">🏠 ${roof}</td></tr>`;
    const{mods,plain}=byRoof[roof];

    // Grid rows: module → pv → inverter columns
    const sortedMods=Object.keys(mods).sort((a,b)=>(parseInt(a.replace(/\D/g,''))||0)-(parseInt(b.replace(/\D/g,''))||0));
    for(const mod of sortedMods){
      h+=`<tr class="hm-group-mod"><td class="td-mod-label">▸ ${mod}</td>`;
      for(let i=0;i<inverters.length;i++) h+=`<td class="td-mod-blank"></td>`;
      h+=`</tr>`;

      const sortedPVs=Object.keys(mods[mod]).sort((a,b)=>(parseInt(a.replace(/\D/g,''))||0)-(parseInt(b.replace(/\D/g,''))||0));
      for(const pv of sortedPVs){
        const rowInvMap=mods[mod][pv];
        const rowVals=Object.values(rowInvMap).map(s=>{const v=s.d[date];return(v!==undefined&&v!==null)?v:null;}).filter(v=>v!==null);
        const rowAvg=rowVals.length?rowVals.reduce((a,b)=>a+b,0)/rowVals.length:null;
        const isRowUnder=cutoff!==null&&rowAvg!==null&&rowAvg<cutoff;
        const anyBL=Object.values(rowInvMap).some(s=>!!blacklist[s.m.label]);
        h+=`<tr class="${anyBL?'blacklisted':''}${isRowUnder&&!anyBL?' underperform-row':''}">`;
        h+=`<td class="td-label" style="padding-left:28px"><span style="color:var(--text-dim);font-size:10px">${mod}-</span>${pv}</td>`;
        for(const inv of inverters){
          const s=rowInvMap[inv];
          if(!s){h+=`<td class="td-cell"><div class="cell-inner cell-empty">—</div></td>`;continue;}
          const v=s.d[date];
          const isBL=!!blacklist[s.m.label];
          if(isBL){h+=`<td class="td-cell"><div class="cell-inner cell-empty" style="opacity:0.4">⊘</div></td>`;continue;}
          if(v===undefined||v===null){h+=`<td class="td-cell"><div class="cell-inner cell-empty">—</div></td>`;continue;}
          const c=perfColor(v);
          h+=`<td class="td-cell${cutoff!==null&&v<cutoff?' underperform-bg':''}"><div class="cell-inner cell-solid" style="background:${c}">${Math.round(v*100)}</div></td>`;
        }
        h+=`</tr>`;
      }
    }

    // Plain rows: strings with no inverter rendered as simple full-span rows
    if(plain.length){
      plain.sort((a,b)=>(a.m.module+a.m.string).localeCompare(b.m.module+b.m.string));
      for(const s of plain){
        const v=s.d[date];
        const ap=v!==undefined&&v!==null?v:null;
        const isBL=!!blacklist[s.m.label];
        const isUnder=cutoff!==null&&ap!==null&&ap<cutoff&&!isBL;
        const c=ap!==null?perfColor(ap):null;
        h+=`<tr class="${isBL?'blacklisted':''}${isUnder?' underperform-row':''}">`;
        h+=`<td class="td-label">${isBL?'⊘ ':''}${s.m.module}-${s.m.string}</td>`;
        // Span remaining columns with single value cell
        h+=`<td colspan="${inverters.length}" class="td-cell" style="text-align:center">`;
        if(isBL) h+=`<div class="cell-inner cell-empty" style="opacity:0.4">⊘</div>`;
        else if(ap===null) h+=`<div class="cell-inner cell-empty">—</div>`;
        else h+=`<div class="cell-inner cell-solid" style="background:${c}">${Math.round(ap*100)}</div>`;
        h+=`</td></tr>`;
      }
    }
  }
  h+='</tbody></table>';wrap.innerHTML=h;
}

// ===================== ANALYSIS =====================
function renderAnalysis(){
  if(currentTab!=='analysis')return;
  const dates=activeDates(),strings=filteredStrings(),threshold=getThreshold();
  lastFleetAvg=getFleetAvg(strings,dates);
  renderStats(strings,dates,threshold);
  renderTrendChart(strings,dates);
  renderDistChart(strings,dates);
  renderTable(strings,dates,threshold);
}
function renderStats(strings,dates,threshold){
  const total=plantStrings().length,filtered=strings.length;
  const active=strings.filter(s=>!blacklist[s.m.label]);
  const perfs=active.map(s=>avgPerf(s,dates)).filter(v=>v!==null);
  const avg=perfs.length?perfs.reduce((a,b)=>a+b,0)/perfs.length:null;
  const _fleetAvg=getFleetAvg(strings,dates);
  const _cutoff=_fleetAvg!==null?_fleetAvg*(1-threshold):null;
  const under=_cutoff!==null?active.filter(s=>avgPerf(s,dates)!==null&&avgPerf(s,dates)<_cutoff).length:0;
  const blCount=strings.filter(s=>!!blacklist[s.m.label]).length;
  document.getElementById('stats-row').innerHTML=`
    <div class="stat-card"><div class="stat-val">${total}</div><div class="stat-label">Total Strings</div></div>
    <div class="stat-card"><div class="stat-val good">${filtered}</div><div class="stat-label">After Filter</div></div>
    <div class="stat-card"><div class="stat-val${under>0?' danger':''}">${under}</div><div class="stat-label">Deviating</div></div>
    <div class="stat-card"><div class="stat-val${_fleetAvg!==null?' good':''}">${_fleetAvg!==null?(_fleetAvg*100).toFixed(1)+'%':'—'}</div><div class="stat-label">Fleet Avg</div></div>
    <div class="stat-card"><div class="stat-val${blCount>0?' warn':''}">${blCount}</div><div class="stat-label">Blacklisted</div></div>`;
}
function setTrendMode(m){trendMode=m;document.getElementById('trend-inv-btn').classList.toggle('active',m==='inverter');document.getElementById('trend-str-btn').classList.toggle('active',m==='strings');renderTrendChart(filteredStrings(),activeDates());}
function setDistMode(m){distMode=m;document.getElementById('dist-cap-btn').classList.toggle('active',m==='capacity');document.getElementById('dist-az-btn').classList.toggle('active',m==='azimuth');renderDistChart(filteredStrings(),activeDates());}
// ===================== HTML TOOLTIP =====================
const ttEl=()=>document.getElementById('chart-tooltip');
const ttTitle=()=>document.getElementById('chart-tooltip-title');
const ttBody=()=>document.getElementById('chart-tooltip-body');
const ttFooter=()=>document.getElementById('chart-tooltip-footer');

function positionTooltip(chart,tooltip){
  const el=ttEl();
  if(!el)return;
  const rect=chart.canvas.getBoundingClientRect();
  let x=rect.left+tooltip.caretX+14;
  let y=rect.top+tooltip.caretY-10;
  // Keep within viewport
  const tw=el.offsetWidth||280,th=el.offsetHeight||200;
  if(x+tw>window.innerWidth-8)x=rect.left+tooltip.caretX-tw-14;
  if(y+th>window.innerHeight-8)y=window.innerHeight-th-8;
  if(y<4)y=4;
  el.style.left=x+'px';el.style.top=y+'px';
}

function externalTooltipTrend(context){
  const{chart,tooltip}=context;
  const el=ttEl();if(!el)return;
  if(tooltip.opacity===0){el.classList.remove('visible');return;}
  const cutoffTrend=lastFleetAvg!==null?lastFleetAvg*(1-getThreshold())*100:null;
  const items=(tooltip.dataPoints||[]).filter(i=>i.parsed.y!==null).sort((a,b)=>a.parsed.y-b.parsed.y);
  if(!items.length){el.classList.remove('visible');return;}
  ttTitle().textContent='📅 '+items[0].label;
  const rows=items.map(i=>{
    const v=i.parsed.y,isUnder=cutoffTrend!==null&&v<cutoffTrend;
    const color=i.dataset.borderColor.replace('99','');
    return`<div class="tt-row"><div class="tt-swatch" style="background:${color}"></div><span class="tt-label">${i.dataset.label}</span><span class="tt-val${isUnder?' under':''}">${v.toFixed(1)}%</span></div>`;
  }).join('');
  ttBody().innerHTML=rows;
  const vals=items.map(i=>i.parsed.y);
  const avg=(vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1);
  const mn=Math.min(...vals).toFixed(1),mx=Math.max(...vals).toFixed(1);
  const ft=ttFooter();ft.style.display='flex';
  ft.innerHTML=`<span>Avg <b>${avg}%</b></span><span>Min <b>${mn}%</b></span><span>Max <b>${mx}%</b></span>`;
  el.classList.add('visible');
  positionTooltip(chart,tooltip);
}

function externalTooltipDist(context){
  const{chart,tooltip}=context;
  const el=ttEl();if(!el)return;
  if(tooltip.opacity===0){el.classList.remove('visible');return;}
  const items=tooltip.dataPoints||[];
  if(!items.length){el.classList.remove('visible');return;}
  const cutoffDist=lastFleetAvg!==null?lastFleetAvg*(1-getThreshold())*100:null;
  const xLabel=distMode==='capacity'?'Cap':'Az';
  const xUnit=distMode==='capacity'?'kWp':'°';
  ttTitle().textContent=`${xLabel}: ${items[0].raw.x} ${xUnit}`;
  ttBody().innerHTML=items.map(i=>{
    const v=i.parsed.y,isUnder=cutoffDist!==null&&v<cutoffDist;
    return`<div class="tt-row"><span class="tt-label">${i.raw.label}</span><span class="tt-val${isUnder?' under':''}">${v.toFixed(1)}%</span></div>`;
  }).join('');
  const ft=ttFooter();ft.style.display='none';
  el.classList.add('visible');
  positionTooltip(chart,tooltip);
}

// Hide tooltip when mouse leaves chart area
function bindTooltipHide(canvas){
  canvas.addEventListener('mouseleave',()=>ttEl()&&ttEl().classList.remove('visible'));
}

function chartColors(){const d=document.body.classList.contains('dark');return{grid:d?'#1e2d45':'#E2E8F0',tick:d?'#64748b':'#6B7A99',legend:d?'#94a3b8':'#6B7A99'};}
function renderTrendChart(strings,dates){
  const ctx=document.getElementById('trend-chart').getContext('2d');
  if(trendChart){trendChart.destroy();trendChart=null;}
  if(!dates.length||!strings.length)return;
  const palette=['#0066FF','#3B82F6','#f59e0b','#ef4444','#8b5cf6','#ec4899','#06b6d4','#84cc16','#f97316','#14b8a6'];
  let datasets=[];
  if(trendMode==='inverter'){
    const byInv={};
    // Check if plant has multiple real roofs (exclude 1 Zone from consideration)
    const uniqueRoofs=new Set(strings.map(s=>s.m.roof).filter(r=>r&&r!=='1 Zone'));
    const multiRoof=uniqueRoofs.size>1;
    for(const s of strings){
      if(!s.m.inverter||s.m.inverter==='N/A')continue; // skip no-inverter strings
      const k=multiRoof?s.m.roof+'/'+s.m.inverter:s.m.inverter;
      if(!byInv[k])byInv[k]=[];byInv[k].push(s);
    }
    let ci=0;
    for(const[k,strs]of Object.entries(byInv)){
      const data=dates.map(d=>{const vals=strs.map(s=>s.d[d]).filter(v=>v!==null&&v!==undefined);return vals.length?vals.reduce((a,b)=>a+b,0)/vals.length*100:null;});
      datasets.push({label:k,data,borderColor:palette[ci%palette.length],backgroundColor:palette[ci%palette.length]+'20',tension:0.3,fill:false,pointRadius:3,borderWidth:2,spanGaps:true});ci++;
    }
  }else{
    const MAX_STRINGS=300;
    const truncated=strings.length>MAX_STRINGS;
    const subset=truncated?strings.slice(0,MAX_STRINGS):strings;
    let ci=0;
    for(const s of subset){
      const data=dates.map(d=>s.d[d]!==undefined?s.d[d]*100:null);
      datasets.push({label:s.m.inverter+'-'+s.m.string,data,borderColor:palette[ci%palette.length]+'99',backgroundColor:'transparent',tension:0.3,fill:false,pointRadius:2,borderWidth:1,spanGaps:true});ci++;
    }
    const titleEl=document.querySelector('.chart-title');
    const warningId='trend-truncate-warn';
    let warn=document.getElementById(warningId);
    if(!warn){warn=document.createElement('span');warn.id=warningId;warn.style.cssText='font-size:10px;color:var(--accent-warn);font-weight:600;margin-left:8px;';titleEl&&titleEl.appendChild(warn);}
    warn.textContent=truncated?`(showing ${MAX_STRINGS} of ${strings.length} strings)`:'';
  }
  const cc=chartColors();
  trendChart=new Chart(ctx,{type:'line',data:{labels:dates.map(d=>d.slice(5)),datasets},options:{responsive:true,maintainAspectRatio:false,interaction:{mode:'index',intersect:false},plugins:{legend:{display:trendMode==='inverter',labels:{color:cc.legend,font:{size:10},boxWidth:12}},tooltip:{enabled:false,external:externalTooltipTrend}},scales:{x:{ticks:{color:cc.tick,font:{size:10}},grid:{color:cc.grid}},y:{min:0,max:100,ticks:{color:cc.tick,font:{size:10},callback:v=>v+'%'},grid:{color:cc.grid}}}}});
  bindTooltipHide(ctx.canvas);
}
function renderDistChart(strings,dates){
  const ctx=document.getElementById('dist-chart').getContext('2d');
  if(distChart){distChart.destroy();distChart=null;}
  if(!dates.length||!strings.length)return;
  const _fa=getFleetAvg(strings,dates);
  const deviation=getThreshold();
  const cutoffPct=_fa!==null?_fa*(1-deviation)*100:null;
  const fleetAvgPct=_fa!==null?_fa*100:null;
  const points=strings.map(s=>{
    const yv=avgPerf(s,dates);
    const xv=distMode==='capacity'?s.m.capacity:s.m.azimuth;
    if(yv===null||xv===null||xv===undefined)return null;
    return{x:xv,y:yv*100,label:s.m.module+'-'+s.m.string};
  }).filter(Boolean);
  const color=distMode==='capacity'?'#0066FF':'#3B82F6';
  const cc2=chartColors();
  distChart=new Chart(ctx,{type:'scatter',data:{datasets:[{label:distMode==='capacity'?'Capacity (kWp)':'Azimuth (°)',data:points,backgroundColor:color+'66',borderColor:color,pointRadius:4,borderWidth:1}]},options:{responsive:true,maintainAspectRatio:false,interaction:{mode:'nearest',intersect:false},plugins:{legend:{display:false},tooltip:{enabled:false,external:externalTooltipDist}},scales:{x:{title:{display:true,text:distMode==='capacity'?'Capacity (kWp)':'Azimuth (°)',color:cc2.tick,font:{size:11}},ticks:{color:cc2.tick,font:{size:10}},grid:{color:cc2.grid}},y:{min:0,max:100,title:{display:true,text:'Avg Perf (%)',color:cc2.tick,font:{size:11}},ticks:{color:cc2.tick,font:{size:10},callback:v=>v+'%'},grid:{color:cc2.grid}}}}});
  bindTooltipHide(ctx.canvas);
  // Draw deviation cutoff line and fleet avg line
  const plugin={id:'threshLine',afterDraw(chart){
    const{ctx,chartArea,scales}=chart;if(!chartArea)return;
    // Fleet avg line
    if(fleetAvgPct!==null){
      const yAvg=scales.y.getPixelForValue(fleetAvgPct);
      ctx.save();ctx.beginPath();ctx.moveTo(chartArea.left,yAvg);ctx.lineTo(chartArea.right,yAvg);
      ctx.strokeStyle='#f59e0b';ctx.lineWidth=1.5;ctx.setLineDash([4,4]);ctx.stroke();
      ctx.fillStyle='#f59e0b';ctx.font='10px IBM Plex Mono';ctx.fillText('Fleet avg '+fleetAvgPct.toFixed(0)+'%',chartArea.left+4,yAvg-4);
      ctx.restore();
    }
    // Deviation cutoff line
    if(cutoffPct!==null){
      const y=scales.y.getPixelForValue(cutoffPct);
      ctx.save();ctx.beginPath();ctx.moveTo(chartArea.left,y);ctx.lineTo(chartArea.right,y);
      ctx.strokeStyle='#ef4444';ctx.lineWidth=2;ctx.setLineDash([6,3]);ctx.stroke();
      ctx.fillStyle='#94a3b8';ctx.font='10px IBM Plex Mono';ctx.fillText('Deviation -'+Math.round(deviation*100)+'% ('+cutoffPct.toFixed(0)+'%)',chartArea.left+4,y-4);
      ctx.restore();
    }
  }};
  distChart.options.plugins.threshLine=true;
  if(!Chart.registry.plugins.get('threshLine'))Chart.register(plugin);
}

// ===================== TABLE =====================
function renderTable(strIn,datesIn,thrIn){
  const strings=strIn||filteredStrings(),dates=datesIn||activeDates(),threshold=thrIn!==undefined?thrIn:getThreshold();
  const search=(document.getElementById('table-search').value||'').toLowerCase();
  const showBL=document.getElementById('show-blacklisted').checked;
  const hilite=document.getElementById('highlight-under').checked;
  let rows=strings.filter(s=>{
    if(!showBL&&blacklist[s.m.label])return false;
    if(search){if(!s.m.label.toLowerCase().includes(search))return false;}
    return true;
  });
  rows.sort((a,b)=>{
    let va,vb;
    if(tableSortCol==='avgPerf'){va=avgPerf(a,dates)||0;vb=avgPerf(b,dates)||0;}
    else if(tableSortCol==='capacity'){va=a.m.capacity||0;vb=b.m.capacity||0;}
    else{va=a.m[tableSortCol]||'';vb=b.m[tableSortCol]||'';}
    return(tableSortAsc?1:-1)*(va<vb?-1:va>vb?1:0);
  });
  const _fleetAvgTbl=getFleetAvg(strings,dates);
  const _cutoffTbl=_fleetAvgTbl!==null?_fleetAvgTbl*(1-threshold):null;
  const cols=[{k:'label',l:'String ID'},{k:'roof',l:'Roof'},{k:'inverter',l:'Inverter'},{k:'tilt',l:'Tilt°'},{k:'azimuth',l:'Az°'},{k:'capacity',l:'Cap kWp'},{k:'avgPerf',l:'Avg Perf'},...dates.map(d=>({k:'d_'+d,l:d.slice(5),date:d}))];
  document.getElementById('table-head').innerHTML='<tr>'+cols.map(c=>`<th onclick="sortTable('${c.k}')">${c.l}${tableSortCol===c.k?(tableSortAsc?' ↑':' ↓'):''}</th>`).join('')+'<th>Notes</th><th>Action</th></tr>';
  const rows_html=rows.map(s=>{
    const ap=avgPerf(s,dates),isBL=!!blacklist[s.m.label];
    const isUnder=_cutoffTbl!==null&&ap!==null&&ap<_cutoffTbl&&!isBL;
    const apColor=ap!==null?perfColor(ap):'#64748b';
    const rc=isBL?'blacklisted':isUnder&&hilite?'underperform-bg':'';
    const note=notes[s.m.label]||'';
    return`<tr class="${rc}">
      <td style="font-size:11px">${isBL?'<span class="bl-badge">⊘</span> ':''}${s.m.label}</td>
      <td>${s.m.roof}</td><td>${s.m.inverter}</td>
      <td>${s.m.tilt??'—'}</td><td>${s.m.azimuth??'—'}</td><td>${s.m.capacity??'—'}</td>
      <td style="white-space:nowrap"><span class="perf-badge" style="background:${apColor}">${ap!==null?Math.round(ap*100)+'%':'—'}</span></td>
      ${dates.map(d=>{const v=s.d[d];if(v===undefined||v===null)return`<td style="text-align:center"><span class="perf-badge empty">—</span></td>`;const c=perfColor(v);return`<td style="text-align:center"><span class="perf-badge" style="background:${c}">${Math.round(v*100)}%</span></td>`;}).join('')}
      <td class="note-cell" onclick="editNote('${s.m.label}',this)">${note||'<span style=\"color:var(--text-dim)\">+add</span>'}</td>
      <td>${isBL?`<button class="action-btn restore-btn" onclick="restoreString('${s.m.label}')">Restore</button>`:`<button class="action-btn remove-btn" onclick="openBlacklistModal('${s.m.label}')">Remove</button>`}</td>
    </tr>`;
  }).join('');
  document.getElementById('table-body').innerHTML=rows_html;
}
function sortTable(col){if(tableSortCol===col)tableSortAsc=!tableSortAsc;else{tableSortCol=col;tableSortAsc=true;}renderTable();}

// ===================== NOTES & BLACKLIST =====================
function editNote(label,cell){
  const cur=notes[label]||'';
  const inp=document.createElement('input');
  inp.className='note-input';inp.value=cur;inp.type='text';
  cell.innerHTML='';cell.appendChild(inp);inp.focus();
  inp.onblur=()=>{const val=inp.value.trim();if(val)notes[label]=val;else delete notes[label];localStorage.setItem('cmes_notes',JSON.stringify(notes));renderTable();};
  inp.onkeydown=e=>{if(e.key==='Enter')inp.blur();if(e.key==='Escape'){inp.value=cur;inp.blur();}};
}
function openBlacklistModal(label){
  blacklistTarget=label;
  document.getElementById('bl-modal-str').textContent='Blacklist: '+label;
  document.getElementById('bl-reason').value='';
  document.getElementById('bl-modal').classList.add('open');
  setTimeout(()=>document.getElementById('bl-reason').focus(),50);
}
function confirmBlacklist(){
  const reason=document.getElementById('bl-reason').value.trim()||'No reason given';
  blacklist[blacklistTarget]={reason,ts:new Date().toISOString()};
  localStorage.setItem('cmes_blacklist',JSON.stringify(blacklist));
  closeModal();renderAnalysis();renderHeatmap();
}
function restoreString(label){delete blacklist[label];localStorage.setItem('cmes_blacklist',JSON.stringify(blacklist));renderAnalysis();renderHeatmap();}
function closeModal(){document.getElementById('bl-modal').classList.remove('open');blacklistTarget=null;}
document.getElementById('bl-modal').addEventListener('click',e=>{if(e.target===e.currentTarget)closeModal();});

// ===================== CLEAR ALL DATA =====================
function openClearModal(){document.getElementById('clear-modal').classList.add('open');}
function closeClearModal(){document.getElementById('clear-modal').classList.remove('open');}
function confirmClearAll(){
  ['cmes_data_overlay','cmes_import_history','cmes_notes','cmes_blacklist'].forEach(k=>localStorage.removeItem(k));
  overlay=null;notes={};blacklist={};
  mergeData();buildPlantSelect();setDefaultDates();updateDatasetInfo();renderHistory();
  activeFilters={roof:new Set(),inv:new Set(),tilt:new Set(),az:new Set(),cap:new Set()};
  const plants=Object.keys(activeData.plants).sort();
  if(plants.length){document.getElementById('plant-select').value=plants[0];onPlantChange();}
  else refreshAllViews();
  closeClearModal();
}
document.getElementById('clear-modal').addEventListener('click',e=>{if(e.target===e.currentTarget)closeClearModal();});

// ===================== IMPORT =====================
function updateDatasetInfo(){
  const d=activeData.dates,p=Object.keys(activeData.plants).length;
  const s=Object.values(activeData.plants).reduce((a,x)=>a+Object.keys(x.strings).length,0);
  document.getElementById('dataset-info').textContent=`${s.toLocaleString()} strings · ${p} plants · ${d[0]} → ${d[d.length-1]} (${d.length} days)`;
}
const MULTI_ROOF=new Set(['PR042','PR043','PR044','PR051','PR052','PR053','PR054','PR055','PR058','PR059','PR063','PR070','PR071','PR077','PR078','PR080','PR082','PR085','PR088']);
function parseLabel(label){
  const parts=label.split('-'),n=parts.length;
  if(n<4)return null;
  const plant=parts[0]+'-'+parts[1];

  // 1. Find string (PVxx) — first match
  let strIdx=-1;
  for(let i=2;i<n;i++){if(/^PV\d+/i.test(parts[i])){strIdx=i;break;}}
  if(strIdx===-1)return null;

  // 2. Find inverter (Ixx or INVxx) — first match before strIdx
  let invIdx=-1;
  for(let i=2;i<strIdx;i++){if(/^(INV|I)\d+/i.test(parts[i])){invIdx=i;break;}}

  // 3. Find module (Mxx) — last match AFTER inverter and BEFORE strIdx
  let modIdx=-1;
  const searchFrom=invIdx!==-1?invIdx+1:2;
  for(let i=searchFrom;i<strIdx;i++){if(/^M\d+/i.test(parts[i]))modIdx=i;}

  // 4. Fallback: if no inverter found but a bare-numeric segment sits just before module
  //    (e.g. CMES-PR044-FacA-06-M01-PV01 → 06 is the inverter)
  //    Do NOT apply this for alphabetic zone names like "Full" — those are roof values.
  if(invIdx===-1&&modIdx>2&&/^\d+$/.test(parts[modIdx-1])){invIdx=modIdx-1;}

  // 5. Roof = everything between plant and inverter
  const roofEnd=invIdx!==-1?invIdx:modIdx!==-1?modIdx:strIdx;
  const roofParts=parts.slice(2,roofEnd);
  const roof=roofParts.length>0?roofParts.join('-'):'1 Zone';
  const inverter=invIdx!==-1?parts[invIdx]:'N/A';
  const module=modIdx!==-1?parts[modIdx]:'N/A';
  const string=parts[strIdx];
  return{plant,roof,inverter,module,string};
}
function buildParsedData(rows){
  const dates=new Set(),plants={};
  for(const r of rows){
    if(!r.label||!r.date)continue;
    const p=parseLabel(r.label);if(!p)continue;
    dates.add(r.date);
    if(!plants[p.plant])plants[p.plant]={strings:{}};
    if(!plants[p.plant].strings[r.label])plants[p.plant].strings[r.label]={m:{label:r.label,plant:p.plant,roof:p.roof,inverter:p.inverter,module:p.module,string:p.string,capacity:r.capacity,tilt:r.tilt,azimuth:r.azimuth},d:{}};
    if(r.perf!==null&&!isNaN(r.perf))plants[p.plant].strings[r.label].d[r.date]=r.perf;
  }
  return{dates:[...dates].sort(),plants};
}
async function handleFile(evt,mode){
  const file=evt.target.files[0];if(!file)return;
  const sid=mode==='append'?'status-append':'status-replace';
  const status=document.getElementById(sid);
  status.className='import-status';status.style.display='block';status.textContent='Parsing…';
  try{
    const data=await parseFile(file);
    if(!data||!data.rows||!data.rows.length)throw new Error('No valid rows found');
    const parsed=buildParsedData(data.rows);
    if(mode==='replace'){archiveSnapshot('replace',file.name,parsed);overlay=parsed;}
    else{
      archiveSnapshot('append',file.name,parsed);
      if(!overlay)overlay={dates:[],plants:{}};
      for(const d of parsed.dates)if(!overlay.dates.includes(d))overlay.dates.push(d);
      overlay.dates.sort();
      for(const[p,pd]of Object.entries(parsed.plants)){
        if(!overlay.plants[p])overlay.plants[p]={strings:{}};
        for(const[l,s]of Object.entries(pd.strings)){
          if(!overlay.plants[p].strings[l])overlay.plants[p].strings[l]={m:s.m,d:{}};
          for(const[d,v]of Object.entries(s.d))if(!(d in overlay.plants[p].strings[l].d))overlay.plants[p].strings[l].d[d]=v;
        }
      }
    }
    lzSave('cmes_data_overlay',{version:DATA_VERSION,data:overlay});
    mergeData();buildPlantSelect();setDefaultDates();updateDatasetInfo();renderHistory();refreshAllViews();
    status.className='import-status ok';status.textContent=`✓ ${mode==='replace'?'Replaced':'Appended'}: ${data.rows.length} rows from "${file.name}"`;
  }catch(e){status.className='import-status err';status.textContent='✗ '+e.message;}
  evt.target.value='';
}
async function parseFile(file){
  return new Promise((resolve,reject)=>{
    const reader=new FileReader();
    reader.onload=e=>{
      try{
        const wb=XLSX.read(e.target.result,{type:'binary',cellDates:true});
        const ws=wb.Sheets[wb.SheetNames[0]];
        const raw=XLSX.utils.sheet_to_json(ws,{raw:false,dateNF:'yyyy-mm-dd'});
        if(!raw.length){resolve({rows:[]});return;}
        const keys=Object.keys(raw[0]);
        const searchKeys=keys.slice(3); // skip A, B, C — only search from column D onward
        const dateKey=keys.find(k=>/date/i.test(k))||keys[0]; // date stays in A by default
        const labelKey=keys[2]; // Column C is always the label
        const perfKey=searchKeys.find(k=>/perf/i.test(k));
        const capKey=searchKeys.find(k=>/cap/i.test(k));
        const tiltKey=searchKeys.find(k=>/tilt/i.test(k));
        const azKey=searchKeys.find(k=>/az/i.test(k));
        const rows=raw.map(r=>({date:r[dateKey]?String(r[dateKey]).slice(0,10):null,label:r[labelKey]||null,perf:r[perfKey]!==undefined?parseFloat(r[perfKey]):null,capacity:r[capKey]!==undefined?parseFloat(r[capKey]):null,tilt:r[tiltKey]!==undefined?parseFloat(r[tiltKey]):null,azimuth:r[azKey]!==undefined?parseFloat(r[azKey]):null})).filter(r=>r.date&&r.label);
        resolve({rows});
      }catch(ex){reject(ex);}
    };
    reader.onerror=()=>reject(new Error('File read failed'));
    reader.readAsBinaryString(file);
  });
}
function archiveSnapshot(type,filename,parsed){
  const strings=Object.values(parsed.plants).reduce((a,p)=>a+Object.keys(p.strings).length,0);
  const history=lzLoad('cmes_import_history',[]);
  history.unshift({ts:new Date().toISOString(),type,filename,strings,dateRange:parsed.dates.length?parsed.dates[0]+' → '+parsed.dates[parsed.dates.length-1]:'—',snapshot:LZString.compressToUTF16(JSON.stringify({dates:parsed.dates,plants:parsed.plants}))});
  while(history.length>5)history.pop();
  lzSave('cmes_import_history',history);
}
function renderHistory(){
  const history=lzLoad('cmes_import_history',[]);
  const tbody=document.getElementById('history-body');
  if(!history.length){tbody.innerHTML='<tr><td colspan="6" style="text-align:center;color:var(--text-dim);padding:20px">No import history yet</td></tr>';return;}
  tbody.innerHTML=history.map((h,i)=>`<tr><td>${new Date(h.ts).toLocaleString()}</td><td><span class="type-badge ${h.type}">${h.type}</span></td><td>${h.filename}</td><td>${(h.strings||0).toLocaleString()}</td><td>${h.dateRange}</td><td><button class="action-btn restore-btn" onclick="restoreSnapshot(${i})">Restore</button></td></tr>`).join('');
}
function restoreSnapshot(idx){
  const history=lzLoad('cmes_import_history',[]);
  const snap=history[idx];if(!snap||!snap.snapshot)return;
  overlay=JSON.parse(LZString.decompressFromUTF16(snap.snapshot));
  lzSave('cmes_data_overlay',{version:DATA_VERSION,data:overlay});
  mergeData();buildPlantSelect();setDefaultDates();updateDatasetInfo();refreshAllViews();
}
['drop-append','drop-replace'].forEach(id=>{
  const el=document.getElementById(id),mode=id.replace('drop-','');
  el.addEventListener('dragover',e=>{e.preventDefault();el.classList.add('drag-over');});
  el.addEventListener('dragleave',()=>el.classList.remove('drag-over'));
  el.addEventListener('drop',e=>{
    e.preventDefault();el.classList.remove('drag-over');
    const file=e.dataTransfer.files[0];
    if(file){const fakeEvt={target:{files:[file],value:''}};handleFile(fakeEvt,mode);}
  });
});

// ===================== THEME =====================
let isDark=false;
function toggleTheme(){
  isDark=!isDark;
  document.body.classList.toggle('dark',isDark);
  document.getElementById('theme-btn').textContent=isDark?'☀️':'🌙';
  localStorage.setItem('cmes_theme',isDark?'dark':'light');
  if(currentTab==='analysis'){renderTrendChart(filteredStrings(),activeDates());renderDistChart(filteredStrings(),activeDates());}
}
function initTheme(){
  const saved=localStorage.getItem('cmes_theme');
  if(saved==='dark'){isDark=true;document.body.classList.add('dark');document.getElementById('theme-btn').textContent='☀️';}
  else{document.getElementById('theme-btn').textContent='🌙';}
}

