initTheme();
init();

// ===================== REPORT TAB =====================
let reportTrendChart=null,reportDistCapChart=null,reportDistAzChart=null;

function initReportTab(){
  // Populate plant select for report
  const plantSel=document.getElementById('report-plant');
  const plants=Object.keys(activeData.plants).sort();
  plantSel.innerHTML=plants.map(p=>`<option value="${p}">${p}</option>`).join('');
  if(currentPlant&&plants.includes(currentPlant))plantSel.value=currentPlant;
  else if(plants.length)plantSel.value=plants[0];
  
  // Set default dates
  const dates=activeData.dates;
  if(dates.length){
    document.getElementById('report-from').value=dates[0];
    document.getElementById('report-to').value=dates[dates.length-1];
  }
}

function getReportPlant(){return document.getElementById('report-plant').value;}
function getReportDates(){
  const from=document.getElementById('report-from').value;
  const to=document.getElementById('report-to').value;
  const exclWeekends=document.getElementById('report-excl-weekends').checked;
  let dates=activeData.dates.filter(d=>d>=from&&d<=to);
  if(exclWeekends)dates=dates.filter(d=>{const day=new Date(d+'T00:00:00').getDay();return day!==0&&day!==6;});
  return dates;
}
function getReportStrings(){
  const plant=getReportPlant();
  if(!plant||!activeData.plants[plant])return[];
  const exclBL=document.getElementById('report-excl-blacklisted').checked;
  let strings=Object.values(activeData.plants[plant].strings);
  if(exclBL)strings=strings.filter(s=>!blacklist[s.m.label]);
  return strings;
}

function onReportConfigChange(){
  if(currentTab==='report')renderReportPreview();
}

function renderReportPreview(){
  const strings=getReportStrings();
  const dates=getReportDates();
  
  if(!strings.length||!dates.length){
    document.getElementById('report-summary-stats').innerHTML='<span style="color:var(--text-dim)">No data available for selected configuration</span>';
    return;
  }
  
  renderReportTrendChart(strings,dates);
  renderReportDistCapChart(strings,dates);
  renderReportDistAzChart(strings,dates);
  renderReportSummary(strings,dates);
  renderReportTable(strings,dates);
}

function renderReportTrendChart(strings,dates){
  const ctx=document.getElementById('report-trend-chart').getContext('2d');
  if(reportTrendChart){reportTrendChart.destroy();reportTrendChart=null;}
  if(!dates.length||!strings.length)return;
  
  const palette=['#0066FF','#3B82F6','#f59e0b','#ef4444','#8b5cf6','#ec4899','#06b6d4','#84cc16','#f97316','#14b8a6'];
  const MAX_STRINGS=50;
  const subset=strings.slice(0,MAX_STRINGS);
  
  const datasets=subset.map((s,i)=>{
    const data=dates.map(d=>s.d[d]!==undefined?s.d[d]*100:null);
    return{
      label:s.m.module+'-'+s.m.string,
      data,
      borderColor:palette[i%palette.length]+'99',
      backgroundColor:'transparent',
      tension:0.3,fill:false,pointRadius:1,borderWidth:1,spanGaps:true
    };
  });
  
  const cc=chartColors();
  reportTrendChart=new Chart(ctx,{
    type:'line',
    data:{labels:dates.map(d=>d.slice(5)),datasets},
    options:{
      responsive:true,maintainAspectRatio:false,
      animation:false,
      plugins:{legend:{display:false},tooltip:{enabled:true,mode:'index',intersect:false}},
      scales:{
        x:{ticks:{color:cc.tick,font:{size:9},maxRotation:45},grid:{color:cc.grid}},
        y:{min:0,max:100,ticks:{color:cc.tick,font:{size:9},callback:v=>v+'%'},grid:{color:cc.grid}}
      }
    }
  });
}

function renderReportDistCapChart(strings,dates){
  const ctx=document.getElementById('report-dist-cap-chart').getContext('2d');
  if(reportDistCapChart){reportDistCapChart.destroy();reportDistCapChart=null;}
  if(!dates.length||!strings.length)return;
  
  const points=strings.map(s=>{
    const yv=avgPerf(s,dates);
    const xv=s.m.capacity;
    if(yv===null||xv===null||xv===undefined)return null;
    return{x:xv,y:yv*100,label:s.m.module+'-'+s.m.string};
  }).filter(Boolean);
  
  const cc=chartColors();
  reportDistCapChart=new Chart(ctx,{
    type:'scatter',
    data:{datasets:[{label:'By Capacity',data:points,backgroundColor:'#0066FF66',borderColor:'#0066FF',pointRadius:3,borderWidth:1}]},
    options:{
      responsive:true,maintainAspectRatio:false,
      animation:false,
      plugins:{legend:{display:false},tooltip:{enabled:true}},
      scales:{
        x:{title:{display:true,text:'Capacity (kWp)',color:cc.tick,font:{size:10}},ticks:{color:cc.tick,font:{size:9}},grid:{color:cc.grid}},
        y:{min:0,max:100,title:{display:true,text:'Avg Perf (%)',color:cc.tick,font:{size:10}},ticks:{color:cc.tick,font:{size:9},callback:v=>v+'%'},grid:{color:cc.grid}}
      }
    }
  });
}

function renderReportDistAzChart(strings,dates){
  const ctx=document.getElementById('report-dist-az-chart').getContext('2d');
  if(reportDistAzChart){reportDistAzChart.destroy();reportDistAzChart=null;}
  if(!dates.length||!strings.length)return;
  
  const points=strings.map(s=>{
    const yv=avgPerf(s,dates);
    const xv=s.m.azimuth;
    if(yv===null||xv===null||xv===undefined)return null;
    return{x:xv,y:yv*100,label:s.m.module+'-'+s.m.string};
  }).filter(Boolean);
  
  const cc=chartColors();
  reportDistAzChart=new Chart(ctx,{
    type:'scatter',
    data:{datasets:[{label:'By Azimuth',data:points,backgroundColor:'#3B82F666',borderColor:'#3B82F6',pointRadius:3,borderWidth:1}]},
    options:{
      responsive:true,maintainAspectRatio:false,
      animation:false,
      plugins:{legend:{display:false},tooltip:{enabled:true}},
      scales:{
        x:{title:{display:true,text:'Azimuth (°)',color:cc.tick,font:{size:10}},ticks:{color:cc.tick,font:{size:9}},grid:{color:cc.grid}},
        y:{min:0,max:100,title:{display:true,text:'Avg Perf (%)',color:cc.tick,font:{size:10}},ticks:{color:cc.tick,font:{size:9},callback:v=>v+'%'},grid:{color:cc.grid}}
      }
    }
  });
}

function renderReportSummary(strings,dates){
  const perfs=strings.map(s=>avgPerf(s,dates)).filter(v=>v!==null);
  const avgP=perfs.length?(perfs.reduce((a,b)=>a+b,0)/perfs.length*100).toFixed(1):'—';
  const minP=perfs.length?(Math.min(...perfs)*100).toFixed(1):'—';
  const maxP=perfs.length?(Math.max(...perfs)*100).toFixed(1):'—';
  const under80=perfs.filter(v=>v<0.8).length;
  
  document.getElementById('report-summary-stats').innerHTML=`
    <div style="flex:1;min-width:100px;text-align:center;padding:8px;background:var(--surface);border-radius:6px;border:1px solid var(--border)">
      <div style="font-size:18px;font-weight:800;color:var(--accent)">${strings.length}</div>
      <div style="font-size:10px;color:var(--text-dim);text-transform:uppercase">Strings</div>
    </div>
    <div style="flex:1;min-width:100px;text-align:center;padding:8px;background:var(--surface);border-radius:6px;border:1px solid var(--border)">
      <div style="font-size:18px;font-weight:800;color:var(--accent)">${avgP}%</div>
      <div style="font-size:10px;color:var(--text-dim);text-transform:uppercase">Avg Perf</div>
    </div>
    <div style="flex:1;min-width:100px;text-align:center;padding:8px;background:var(--surface);border-radius:6px;border:1px solid var(--border)">
      <div style="font-size:18px;font-weight:800;color:#16a34a">${maxP}%</div>
      <div style="font-size:10px;color:var(--text-dim);text-transform:uppercase">Max</div>
    </div>
    <div style="flex:1;min-width:100px;text-align:center;padding:8px;background:var(--surface);border-radius:6px;border:1px solid var(--border)">
      <div style="font-size:18px;font-weight:800;color:var(--accent-danger)">${minP}%</div>
      <div style="font-size:10px;color:var(--text-dim);text-transform:uppercase">Min</div>
    </div>
    <div style="flex:1;min-width:100px;text-align:center;padding:8px;background:var(--surface);border-radius:6px;border:1px solid var(--border)">
      <div style="font-size:18px;font-weight:800;color:${under80>0?'var(--accent-danger)':'var(--text)'}">${under80}</div>
      <div style="font-size:10px;color:var(--text-dim);text-transform:uppercase">&lt;80%</div>
    </div>
  `;
}

function renderReportTable(strings,dates){
  // Sort by average performance (lowest first)
  const sorted=[...strings].map(s=>({s,avg:avgPerf(s,dates)}))
    .sort((a,b)=>(a.avg===null?1:b.avg===null?-1:a.avg-b.avg))
    .map(x=>x.s);
  
  document.getElementById('report-table-head').innerHTML=`
    <tr>
      <th>#</th>
      <th>String ID</th>
      <th>Roof</th>
      <th>Inverter</th>
      <th>Module</th>
      <th>Capacity</th>
      <th>Tilt</th>
      <th>Azimuth</th>
      <th>Avg Perf</th>
    </tr>`;
  
  document.getElementById('report-table-body').innerHTML=sorted.slice(0,100).map((s,i)=>{
    const ap=avgPerf(s,dates);
    const apPct=ap!==null?(ap*100).toFixed(1)+'%':'—';
    const color=ap!==null?perfColor(ap):'#64748b';
    return`<tr>
      <td>${i+1}</td>
      <td style="font-family:var(--font-mono);font-size:10px">${s.m.label}</td>
      <td>${s.m.roof}</td>
      <td>${s.m.inverter}</td>
      <td>${s.m.module}</td>
      <td>${s.m.capacity??'—'}</td>
      <td>${s.m.tilt??'—'}°</td>
      <td>${s.m.azimuth??'—'}°</td>
      <td><span style="display:inline-block;padding:2px 8px;border-radius:4px;background:${color};color:#fff;font-weight:700;font-size:11px">${apPct}</span></td>
    </tr>`;
  }).join('');
}

async function generatePDFReport(){
  const btn=document.getElementById('generate-pdf-btn');
  const status=document.getElementById('report-status');
  
  const plant=getReportPlant();
  const dates=getReportDates();
  const strings=getReportStrings();
  
  // Validation
  if(!plant){
    status.className='report-status error';
    status.textContent='✗ Please select a plant';
    return;
  }
  if(!dates.length){
    status.className='report-status error';
    status.textContent='✗ No dates in selected range';
    return;
  }
  if(!strings.length){
    status.className='report-status error';
    status.textContent='✗ No strings available for selected plant';
    return;
  }
  
  btn.disabled=true;
  status.className='report-status report-loading';
  status.innerHTML='<div class="spinner"></div> Generating PDF...';
  
  // Small delay to let the UI update
  await new Promise(r=>setTimeout(r,50));
  
  try{
    const{jsPDF}=window.jspdf;
    const pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'});
    
    const fromDate=document.getElementById('report-from').value;
    const toDate=document.getElementById('report-to').value;
    
    let y=15;
    const marginLeft=15;
    const pageWidth=210;
    const contentWidth=pageWidth-30;
    
    // ===== HEADER =====
    pdf.setFillColor(0,102,255);
    pdf.rect(0,0,pageWidth,35,'F');
    
    pdf.setFont('helvetica','bold');
    pdf.setFontSize(18);
    pdf.setTextColor(255,255,255);
    pdf.text('CMES Solar String Performance Report',marginLeft,18);
    
    pdf.setFontSize(11);
    pdf.setFont('helvetica','normal');
    pdf.text(`Plant: ${plant}  |  Period: ${fromDate} to ${toDate}  |  Strings: ${strings.length}`,marginLeft,28);
    
    y=45;
    
    // ===== SUMMARY STATS =====
    pdf.setFontSize(12);
    pdf.setFont('helvetica','bold');
    pdf.setTextColor(26,34,54);
    pdf.text('Summary Statistics',marginLeft,y);
    y+=8;
    
    const perfs=strings.map(s=>avgPerf(s,dates)).filter(v=>v!==null);
    const avgP=perfs.length?(perfs.reduce((a,b)=>a+b,0)/perfs.length*100).toFixed(1):'—';
    const minP=perfs.length?(Math.min(...perfs)*100).toFixed(1):'—';
    const maxP=perfs.length?(Math.max(...perfs)*100).toFixed(1):'—';
    const _pdfFleetAvg=perfs.length?perfs.reduce((a,b)=>a+b,0)/perfs.length:null;
    const _pdfCutoff=_pdfFleetAvg!==null?_pdfFleetAvg*(1-getThreshold()):null;
    const deviating=_pdfCutoff!==null?perfs.filter(v=>v<_pdfCutoff).length:0;

    pdf.setFontSize(10);
    pdf.setFont('helvetica','normal');
    const statsText=`Total Strings: ${strings.length}  |  Fleet Avg: ${avgP}%  |  Min: ${minP}%  |  Max: ${maxP}%  |  Deviating (>${Math.round(getThreshold()*100)}% below avg): ${deviating}`;
    pdf.text(statsText,marginLeft,y);
    y+=12;
    
    // ===== CHART 1: Performance Trend =====
    pdf.setFontSize(11);
    pdf.setFont('helvetica','bold');
    pdf.text('1. Performance Trend (Individual Strings)',marginLeft,y);
    y+=5;
    
    const trendCanvas=document.getElementById('report-trend-chart');
    if(trendCanvas&&reportTrendChart){
      const trendImg=trendCanvas.toDataURL('image/png',1.0);
      pdf.addImage(trendImg,'PNG',marginLeft,y,contentWidth,50);
      y+=55;
    }
    
    // ===== CHART 2: Distribution by Capacity =====
    pdf.setFont('helvetica','bold');
    pdf.text('2. Performance Distribution (By Capacity)',marginLeft,y);
    y+=5;
    
    const capCanvas=document.getElementById('report-dist-cap-chart');
    if(capCanvas&&reportDistCapChart){
      const capImg=capCanvas.toDataURL('image/png',1.0);
      pdf.addImage(capImg,'PNG',marginLeft,y,contentWidth/2-5,45);
    }
    
    // ===== CHART 3: Distribution by Azimuth =====
    pdf.setFont('helvetica','bold');
    pdf.text('3. By Azimuth',marginLeft+contentWidth/2+5,y);
    
    const azCanvas=document.getElementById('report-dist-az-chart');
    if(azCanvas&&reportDistAzChart){
      const azImg=azCanvas.toDataURL('image/png',1.0);
      pdf.addImage(azImg,'PNG',marginLeft+contentWidth/2+5,y+5,contentWidth/2-5,45);
    }
    y+=55;
    
    // ===== NEW PAGE FOR TABLE =====
    pdf.addPage();
    y=15;
    
    pdf.setFillColor(0,102,255);
    pdf.rect(0,0,pageWidth,20,'F');
    pdf.setFontSize(14);
    pdf.setFont('helvetica','bold');
    pdf.setTextColor(255,255,255);
    pdf.text('4. String Details (Lowest Performing First)',marginLeft,13);
    
    y=28;
    
    // Table header
    const colWidths=[8,50,25,18,18,18,18,25];
    const headers=['#','String ID','Roof','INV','Cap','Tilt','Az','Perf'];
    
    pdf.setFillColor(240,244,248);
    pdf.rect(marginLeft,y-5,contentWidth,8,'F');
    
    pdf.setFontSize(8);
    pdf.setFont('helvetica','bold');
    pdf.setTextColor(107,122,153);
    
    let xPos=marginLeft;
    headers.forEach((h,i)=>{
      pdf.text(h,xPos+1,y);
      xPos+=colWidths[i];
    });
    y+=6;
    
    // Sort strings by performance (lowest first)
    const sorted=[...strings].map(s=>({s,avg:avgPerf(s,dates)}))
      .sort((a,b)=>(a.avg===null?1:b.avg===null?-1:a.avg-b.avg))
      .map(x=>x.s);
    
    pdf.setFont('helvetica','normal');
    pdf.setFontSize(7);
    
    let rowCount=0;
    const maxRowsPerPage=45;
    
    for(const s of sorted){
      if(rowCount>=maxRowsPerPage&&y>250){
        pdf.addPage();
        y=15;
        rowCount=0;
        
        // Repeat header on new page
        pdf.setFillColor(240,244,248);
        pdf.rect(marginLeft,y-5,contentWidth,8,'F');
        pdf.setFont('helvetica','bold');
        pdf.setFontSize(8);
        pdf.setTextColor(107,122,153);
        xPos=marginLeft;
        headers.forEach((h,i)=>{
          pdf.text(h,xPos+1,y);
          xPos+=colWidths[i];
        });
        y+=6;
        pdf.setFont('helvetica','normal');
        pdf.setFontSize(7);
      }
      
      const ap=avgPerf(s,dates);
      const apPct=ap!==null?(ap*100).toFixed(1)+'%':'—';
      
      // Alternate row background
      if(rowCount%2===0){
        pdf.setFillColor(250,251,252);
        pdf.rect(marginLeft,y-3,contentWidth,5,'F');
      }
      
      // Highlight low performers
      if(ap!==null&&ap<0.7){
        pdf.setTextColor(239,68,68);
      }else if(ap!==null&&ap<0.85){
        pdf.setTextColor(245,158,11);
      }else{
        pdf.setTextColor(26,34,54);
      }
      
      xPos=marginLeft;
      const rowData=[
        String(rowCount+1),
        s.m.label.substring(0,30),
        (s.m.roof||'—').substring(0,12),
        s.m.inverter||'—',
        s.m.capacity?s.m.capacity.toFixed(2):'—',
        s.m.tilt?s.m.tilt+'°':'—',
        s.m.azimuth?s.m.azimuth+'°':'—',
        apPct
      ];
      
      rowData.forEach((d,i)=>{
        pdf.text(String(d),xPos+1,y);
        xPos+=colWidths[i];
      });
      
      y+=5;
      rowCount++;
      
      if(rowCount>=200)break; // Limit to 200 strings for performance
    }
    
    // Footer on last page
    const pageCount=pdf.internal.getNumberOfPages();
    for(let i=1;i<=pageCount;i++){
      pdf.setPage(i);
      pdf.setFontSize(8);
      pdf.setTextColor(107,122,153);
      pdf.text(`Page ${i} of ${pageCount}`,pageWidth-30,287);
      pdf.text(`Generated: ${new Date().toLocaleString()}`,marginLeft,287);
    }
    
    // Save
    const filename=`CMES_Report_${plant}_${fromDate}_${toDate}.pdf`;
    pdf.save(filename);
    
    status.className='report-status success';
    status.textContent=`✓ Report saved: ${filename}`;
    
  }catch(err){
    console.error('PDF generation error:',err);
    status.className='report-status error';
    status.textContent='✗ Error: '+err.message;
  }finally{
    btn.disabled=false;
  }
}

// ===================== AI ASSISTANT =====================
let aiMessages=[];

function saveAIKey(){
  const key=document.getElementById('ai-api-key').value.trim();
  if(key){localStorage.setItem('cmes_openai_key',key);document.getElementById('ai-key-hint').textContent='saved';setTimeout(()=>{document.getElementById('ai-key-hint').textContent='';},1500);}
  else localStorage.removeItem('cmes_openai_key');
}

function initAITab(){
  const saved=localStorage.getItem('cmes_openai_key');
  if(saved)document.getElementById('ai-api-key').value=saved;
  updateAIContextBar();
  if(aiMessages.length===0)runAnomalyCheck();
}

// ── ANOMALY RULES ENGINE (no API required) ──────────────────────────────────

function scanAnomalies(threshold){
  // Returns { findings, invAvgs } grouped by plant
  const dates=activeData.dates;
  const plantResults={};   // plant → { invAvgs:{}, findings:[] }

  for(const p of Object.keys(activeData.plants)){
    const strings=Object.values(activeData.plants[p].strings).filter(s=>!blacklist[s.m.label]);
    // ── Pre-compute inverter group averages ──────────────────────────────
    const invGroups={};
    for(const s of strings){
      const inv=s.m.inverter||'N/A';
      if(!invGroups[inv])invGroups[inv]=[];
      const v=avgPerf(s,dates);
      if(v!==null)invGroups[inv].push(v);
    }
    const invAvgs={};
    for(const[inv,vals]of Object.entries(invGroups))
      invAvgs[inv]=vals.reduce((a,b)=>a+b,0)/vals.length;

    const findings=[];
    for(const s of strings){
      const inv=s.m.inverter||'N/A';
      const sAvg=avgPerf(s,dates);

      // R1 — Mất công suất: bất kỳ ngày nào ≤5%
      const zeroDays=dates.filter(d=>s.d[d]!==undefined&&s.d[d]<=5);

      // R2 — Giảm đột ngột: giảm ≥ threshold pp trong 1 ngày
      const suddenDrops=[];
      for(let i=1;i<dates.length;i++){
        const prev=s.d[dates[i-1]],curr=s.d[dates[i]];
        if(prev!=null&&curr!=null&&(prev-curr)>=threshold)
          suddenDrops.push({prevDate:dates[i-1],date:dates[i],prevVal:prev,currVal:curr,drop:prev-curr});
      }

      // R3 — Lệch nhóm INV: TB string thấp hơn TB inverter ≥ threshold pp
      const invMean=invAvgs[inv]??null;
      const peerDev=(sAvg!==null&&invMean!==null)?(invMean-sAvg):null;
      const isPeerDev=peerDev!==null&&peerDev>=threshold;

      // R4 — Thấp kéo dài: ≥3 ngày liên tiếp <70%
      let maxConsec=0,cur=0;
      for(const d of dates){
        if(s.d[d]!==undefined&&s.d[d]<70){cur++;maxConsec=Math.max(maxConsec,cur);}
        else cur=0;
      }
      const isLongLow=maxConsec>=3;

      const rules=[];
      if(zeroDays.length)rules.push({code:'R1',label:'Mất công suất',detail:`${zeroDays.length} ngày ≤5%`});
      if(suddenDrops.length)rules.push({code:'R2',label:'Giảm đột ngột',detail:`${suddenDrops.length} sự kiện`});
      if(isPeerDev)rules.push({code:'R3',label:'Lệch nhóm INV',detail:`↓${peerDev.toFixed(1)}pp so với INV`});
      if(isLongLow)rules.push({code:'R4',label:'Thấp kéo dài',detail:`${maxConsec} ngày liên tiếp <70%`});

      if(rules.length)findings.push({label:s.m.label,plant:p,inverter:inv,avg:sAvg,peerDev,rules,suddenDrops,zeroDays,maxConsec});
    }
    if(findings.length||Object.keys(invAvgs).length)
      plantResults[p]={invAvgs,findings,totalStrings:strings.length};
  }
  return plantResults;
}

function generateAnomalyMarkdown(plantResults,threshold){
  const now=new Date().toLocaleString('vi-VN');
  const dates=activeData.dates;
  const allFindings=Object.values(plantResults).flatMap(r=>r.findings);

  if(allFindings.length===0)
    return`## ✅ Hệ Thống Hoạt Động Bình Thường\n\n**Thời điểm:** ${now}\n\nKhông phát hiện bất thường nào với ngưỡng ≥${threshold}pp trên toàn bộ string.`;

  const countBy=code=>allFindings.filter(f=>f.rules.some(r=>r.code===code)).length;
  const L=[];

  // ── Header ────────────────────────────────────────────────────────────────
  L.push(`## 🔍 Báo Cáo Bất Thường Hệ Thống Điện Mặt Trời`);
  L.push(`**Thời điểm:** ${now} | **Kỳ phân tích:** ${dates[0]} → ${dates[dates.length-1]} | **Ngưỡng:** ≥${threshold}pp`);
  L.push('');

  // ── Summary table ─────────────────────────────────────────────────────────
  L.push(`### 📊 Tổng Quan`);
  L.push(`| Quy tắc | Mô tả | Số string |`);
  L.push(`|---|---|---|`);
  L.push(`| R1 | ⚡ Mất công suất (≤5% bất kỳ ngày) | **${countBy('R1')}** |`);
  L.push(`| R2 | 📉 Giảm đột ngột (≥${threshold}pp/ngày) | **${countBy('R2')}** |`);
  L.push(`| R3 | 🔄 Lệch nhóm INV (≥${threshold}pp) | **${countBy('R3')}** |`);
  L.push(`| R4 | ⏳ Thấp kéo dài (≥3 ngày <70%) | **${countBy('R4')}** |`);
  L.push(`| — | **Tổng string bất thường** | **${allFindings.length}** |`);
  L.push('');

  // ── Per Plant ─────────────────────────────────────────────────────────────
  for(const[plant,{invAvgs,findings,totalStrings}]of Object.entries(plantResults).sort()){
    if(!findings.length)continue;
    const errRate=(findings.length/totalStrings*100).toFixed(0);
    L.push(`## 🏭 Plant: ${plant} — ${findings.length}/${totalStrings} string bất thường (${errRate}%)`);
    L.push('');

    // Group by inverter
    const byInv={};
    for(const f of findings){if(!byInv[f.inverter])byInv[f.inverter]=[];byInv[f.inverter].push(f);}

    for(const[inv,items]of Object.entries(byInv).sort()){
      const invMean=invAvgs[inv];
      const invLabel=invMean!==undefined?` — TB nhóm: **${invMean.toFixed(1)}%**`:'';
      L.push(`### ⚡ ${inv}${invLabel}`);

      // String table
      L.push(`| String | TB Hiệu suất | Lệch INV | Bất thường phát hiện |`);
      L.push(`|---|---|---|---|`);
      for(const f of items.sort((a,b)=>(a.avg??100)-(b.avg??100))){
        const avgStr=f.avg!==null?`${f.avg.toFixed(1)}%`:'N/A';
        const devStr=f.peerDev!==null&&f.peerDev>0?`↓${f.peerDev.toFixed(1)}pp`:'—';
        const ruleStr=f.rules.map(r=>`${r.label}`).join(', ');
        L.push(`| **${f.label}** | ${avgStr} | ${devStr} | ${ruleStr} |`);
      }
      L.push('');

      // Event details
      for(const f of items){
        if(f.zeroDays.length)
          L.push(`- 🔴 **${f.label}** — Mất công suất tại: ${f.zeroDays.join(', ')}`);
        for(const e of f.suddenDrops)
          L.push(`- 📉 **${f.label}** — ${e.prevDate}: **${e.prevVal.toFixed(1)}%** → ${e.date}: **${e.currVal.toFixed(1)}%** (↓${e.drop.toFixed(1)}pp)`);
        if(f.maxConsec>=3&&!f.suddenDrops.length&&!f.zeroDays.length)
          L.push(`- ⏳ **${f.label}** — ${f.maxConsec} ngày liên tiếp dưới 70% (TB: ${f.avg!==null?f.avg.toFixed(1):'N/A'}%)`);
      }
      L.push('');
    }
  }

  // ── Nhận định nhanh ───────────────────────────────────────────────────────
  L.push(`## 🔎 Nhận Định Nhanh — O&M`);
  const r1=allFindings.filter(f=>f.rules.some(r=>r.code==='R1'));
  if(r1.length)
    L.push(`- ⚠️ **${r1.length} string mất công suất hoàn toàn** (≤5%): ${r1.map(f=>f.label).join(', ')} → Kiểm tra ngay CB, fuse, connector hoặc module bị lỗi.`);

  for(const[plant,{findings,totalStrings}]of Object.entries(plantResults)){
    const ratio=findings.length/totalStrings;
    if(ratio>=0.3&&findings.length>=3)
      L.push(`- 🔴 **${plant}** tỷ lệ lỗi cao bất thường: ${findings.length}/${totalStrings} string (${(ratio*100).toFixed(0)}%) → Nghi ngờ lỗi hệ thống cấp cao (inverter, tủ điện, đường dây chính).`);
  }

  // Inverters where all strings are flagged
  for(const[plant,{invAvgs,findings}]of Object.entries(plantResults)){
    const byInv={};
    for(const f of findings){if(!byInv[f.inverter])byInv[f.inverter]=[];byInv[f.inverter].push(f);}
    const allStrByInv={};
    for(const f of Object.values(activeData.plants[plant].strings).filter(s=>!blacklist[s.m.label]))
      {const inv=s.m.inverter||'N/A';if(!allStrByInv[inv])allStrByInv[inv]=0;allStrByInv[inv]++;}
    for(const[inv,items]of Object.entries(byInv)){
      if(allStrByInv[inv]&&items.length>=allStrByInv[inv]&&items.length>=2)
        L.push(`- 🚨 **${plant} / ${inv}** toàn bộ ${items.length} string đều bất thường → Nghi ngờ lỗi MPPT hoặc inverter bị hỏng.`);
    }
  }

  if(!r1.length&&!allFindings.some((_,__,arr)=>arr.length/Object.values(plantResults).reduce((s,r)=>s+r.totalStrings,0)>=0.3))
    L.push(`- ✅ Không có dấu hiệu lỗi hệ thống nghiêm trọng. Các bất thường mang tính cục bộ, ưu tiên kiểm tra định kỳ.`);

  return L.join('\n');
}

function runAnomalyCheck(){
  if(!activeData){appendAIMsg('assistant','⚠️ Chưa có dữ liệu. Vui lòng import dữ liệu trước.',true);return;}
  const threshold=parseFloat(document.getElementById('anomaly-threshold').value)||15;
  const plantResults=scanAnomalies(threshold);
  const md=generateAnomalyMarkdown(plantResults,threshold);
  appendAIMsg('assistant',md,false,true);
}

function updateAIContextBar(){
  const el=document.getElementById('ai-context-bar');
  if(!el)return;
  if(!activeData){el.textContent='No data loaded';return;}
  const plants=Object.keys(activeData.plants);
  const totalStrings=plants.reduce((a,p)=>a+Object.keys(activeData.plants[p].strings).length,0);
  const dates=activeData.dates;
  const plant=currentPlant||'all plants';
  el.textContent=`Context: ${plant} · ${totalStrings} strings · ${dates.length} dates (${dates[0]} → ${dates[dates.length-1]}) · ${Object.keys(blacklist).length} blacklisted`;
}

function buildAIContext(){
  if(!activeData)return'No solar data is loaded.';
  const plants=Object.keys(activeData.plants).sort();
  const dates=activeData.dates;
  const recentDates=dates.slice(-14);
  const threshold=parseFloat(document.getElementById('threshold-val').textContent)||20;
  const lines=[];
  lines.push(`Dataset: ${plants.length} plant(s), ${dates.length} dates from ${dates[0]} to ${dates[dates.length-1]}.`);
  lines.push(`Blacklisted strings: ${Object.keys(blacklist).length>0?Object.entries(blacklist).map(([k,v])=>`${k}(${v||'no reason'})`).join(', '):'none'}.`);
  lines.push(`Deviation threshold: ${threshold}%.`);
  lines.push('');
  for(const p of plants){
    const pd=activeData.plants[p];
    const strings=Object.values(pd.strings);
    const active=strings.filter(s=>!blacklist[s.m.label]);
    const perfs=active.map(s=>avgPerf(s,dates)).filter(v=>v!==null);
    const fleet=perfs.length?(perfs.reduce((a,b)=>a+b,0)/perfs.length).toFixed(1):'N/A';
    const under70=perfs.filter(v=>v<70).length;
    const under85=perfs.filter(v=>v<85).length;
    lines.push(`Plant ${p}: ${active.length} active strings, fleet avg ${fleet}%, ${under70} strings <70%, ${under85} strings <85%.`);
    const invMap={};
    for(const s of active){const inv=s.m.inverter||'N/A';if(!invMap[inv])invMap[inv]=[];const v=avgPerf(s,dates);if(v!==null)invMap[inv].push(v);}
    const invSummary=Object.entries(invMap).sort((a,b)=>a[0].localeCompare(b[0])).map(([inv,vals])=>`${inv}:${(vals.reduce((a,b)=>a+b,0)/vals.length).toFixed(1)}%`).join(', ');
    if(invSummary)lines.push(`  Inverter averages: ${invSummary}`);
    const worst=active.map(s=>({label:s.m.label,avg:avgPerf(s,dates),inv:s.m.inverter})).filter(x=>x.avg!==null).sort((a,b)=>a.avg-b.avg).slice(0,15);
    if(worst.length)lines.push(`  Worst strings: ${worst.map(x=>`${x.label}(${x.avg.toFixed(1)}%)`).join(', ')}`);
    lines.push(`  Per-string data (last ${recentDates.length} dates: ${recentDates.join(',')})`);
    for(const s of active.slice(0,80)){
      const daily=recentDates.map(d=>s.d[d]!==undefined?s.d[d].toFixed(0):'-').join(',');
      const avg=avgPerf(s,recentDates);
      lines.push(`    ${s.m.label} inv=${s.m.inverter||'N/A'} cap=${s.m.capacity||'N/A'} tilt=${s.m.tilt||'N/A'} az=${s.m.azimuth||'N/A'} avg=${avg!==null?avg.toFixed(1):'N/A'}% daily=[${daily}]`);
    }
    if(active.length>80)lines.push(`    ...and ${active.length-80} more strings.`);
    lines.push('');
  }
  return lines.join('\n');
}

function renderMarkdown(md){
  let h=md.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
  // Tables
  h=h.replace(/((?:\|[^\n]+\|\n?)+)/g,blk=>{
    const rows=blk.trim().split('\n');let t='<table class="ai-md-table">',hDone=false;
    for(const r of rows){
      if(/^\|[\s\-:|]+\|$/.test(r)){hDone=true;continue;}
      const cols=r.split('|').slice(1,-1).map(c=>c.trim());
      const tag=hDone?'td':'th';
      t+='<tr>'+cols.map(c=>`<${tag}>${c}</${tag}>`).join('')+'</tr>';
      if(!hDone)hDone=true;
    }
    return t+'</table>\n';
  });
  // Headings
  h=h.replace(/^### (.+)$/gm,'<h3 class="ai-md-h3">$1</h3>');
  h=h.replace(/^## (.+)$/gm,'<h2 class="ai-md-h2">$1</h2>');
  h=h.replace(/^# (.+)$/gm,'<h2 class="ai-md-h2">$1</h2>');
  // Bold / italic / code
  h=h.replace(/\*\*\*([^*]+)\*\*\*/g,'<strong><em>$1</em></strong>');
  h=h.replace(/\*\*([^*\n]+)\*\*/g,'<strong>$1</strong>');
  h=h.replace(/\*([^*\n]+)\*/g,'<em>$1</em>');
  h=h.replace(/`([^`\n]+)`/g,'<code class="ai-md-code">$1</code>');
  // Lists
  h=h.replace(/((?:^[-*] .+$\n?)+)/gm,blk=>{
    const items=blk.trim().split('\n').map(l=>`<li>${l.replace(/^[-*] /,'')}</li>`).join('');
    return `<ul class="ai-md-ul">${items}</ul>\n`;
  });
  h=h.replace(/((?:^\d+\. .+$\n?)+)/gm,blk=>{
    const items=blk.trim().split('\n').map(l=>`<li>${l.replace(/^\d+\. /,'')}</li>`).join('');
    return `<ol class="ai-md-ol">${items}</ol>\n`;
  });
  // Paragraphs
  h=h.split(/\n\n+/).map(b=>{
    b=b.trim();if(!b)return'';
    if(/^<(h[1-6]|ul|ol|table)/.test(b))return b;
    return'<p>'+b.replace(/\n/g,'<br>')+'</p>';
  }).join('\n');
  return h;
}

function appendAIMsg(role,text,isError,markdown=false){
  const msgsEl=document.getElementById('ai-messages');
  const welcome=msgsEl.querySelector('.ai-welcome');
  if(welcome)welcome.remove();
  const cls=isError?'error':role;
  const label=role==='user'?'Bạn':'AI Assistant';
  const div=document.createElement('div');
  div.className=`ai-msg ${cls}`;
  div.innerHTML=`<div class="ai-msg-label">${label}</div><div class="ai-msg-bubble${markdown?' has-markdown':''}"></div>`;
  const bubble=div.querySelector('.ai-msg-bubble');
  if(markdown)bubble.innerHTML=renderMarkdown(text);
  else bubble.textContent=text;
  msgsEl.appendChild(div);
  msgsEl.scrollTop=msgsEl.scrollHeight;
  return div;
}

function onAIKeydown(e){
  if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();sendAIMessage();}
}

async function sendAIMessage(){
  const input=document.getElementById('ai-input');
  const sendBtn=document.getElementById('ai-send-btn');
  const text=input.value.trim();
  if(!text)return;
  const apiKey=document.getElementById('ai-api-key').value.trim()||localStorage.getItem('cmes_openai_key')||'';
  if(!apiKey){appendAIMsg('assistant','Please enter your OpenAI API key above.',true);return;}
  input.value='';
  sendBtn.disabled=true;
  aiMessages.push({role:'user',content:text});
  appendAIMsg('user',text,false);
  const thinkingDiv=appendAIMsg('assistant','Thinking…',false);
  thinkingDiv.style.opacity='0.5';
  try{
    const systemPrompt=`You are an AI assistant embedded in a solar string performance monitoring dashboard (CMES Monitor). You have access to the following live dataset snapshot:\n\n${buildAIContext()}\n\nAnswer questions about this data concisely and precisely using the numbers provided. When listing strings, sort by performance (worst first). If data is insufficient to answer, say so clearly.`;
    const res=await fetch('https://api.openai.com/v1/chat/completions',{
      method:'POST',
      headers:{'Authorization':`Bearer ${apiKey}`,'content-type':'application/json'},
      body:JSON.stringify({
        model:'gpt-4o-mini',
        messages:[{role:'system',content:systemPrompt},...aiMessages.slice(-20)]
      })
    });
    const data=await res.json();
    thinkingDiv.remove();
    if(!res.ok){
      const errMsg=data?.error?.message||`API error ${res.status}`;
      appendAIMsg('assistant',errMsg,true);
      aiMessages.pop();
    }else{
      const reply=data.choices?.[0]?.message?.content||'(no response)';
      aiMessages.push({role:'assistant',content:reply});
      appendAIMsg('assistant',reply,false,true);
    }
  }catch(err){
    thinkingDiv.remove();
    appendAIMsg('assistant',`Network error: ${err.message}`,true);
    aiMessages.pop();
  }finally{
    sendBtn.disabled=false;
    input.focus();
  }
}
